,p_process_sequence=>20
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Create MCP Handler'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'declare',
'    l_module_name varchar2(80);',
'',
'    C_POST_SOURCE constant varchar2(32767) := ',
'q''~declare',
'    l_response    blob;',
'    l_session_id  varchar2(128);',
'    l_status_code number;',
'    l_request     blob;',
'begin',
'    l_request := :body;',
'    oj_mcp_app_server.ords_handler(',
'        p_script_name  => owa_util.get_cgi_env(''SCRIPT_NAME'') || owa_util.get_cgi_env(''PATH_INFO'') ',
'        ,p_username    => :current_user',
'        ,p_request     => l_request',
'        ,p_response    => l_response',
'        ,p_session_id  => l_session_id',
'        ,p_status_code => l_status_code',
'    );',
'    /*',
'     * Return the response to the caller.',
'     */',
'    :status_code := l_status_code;',
'    sys.htp.init;',
'    sys.htp.p(''Content-Type: application/json'');',
'    if l_session_id is not null then',
'        sys.htp.p(''Mcp-Session-Id: '' || l_session_id);',
'    end if;',
'    if l_response is not null and dbms_lob.getlength(l_response) > 0 then',
'        sys.htp.p(''Content-Length: '' || dbms_lob.getlength(l_response));',
'        sys.owa_util.http_header_close;',
'        sys.wpg_docload.download_file(l_response);',
'    else',
'        sys.owa_util.http_header_close;',
'    end if;',
'    commit;',
'end;'');~'';',
'',
'    C_DELETE_SOURCE constant varchar2(32767) :=',
'q''~declare',
'    l_session_id varchar2(128);',
'begin',
'    l_session_id := owa_util.get_cgi_env(''Mcp-Session-Id'');',
'    if l_session_id is not null then',
'        apex_session.delete_session(l_session_id);',
'    end if;',
'    :status_code := 204;',
'end;~'';',
'',
'begin',
'    l_module_name := lower(:P3_MODULE_NAME);',
'    ords.define_service(',
'        p_module_name    => l_module_name,',
'        p_base_path      => apex_string.format(''/%s/'', l_module_name),',
'        p_pattern        => ''mcp'',',
'        p_method         => ''POST'',',
'        p_source_type    => ''plsql/block'',',
'        -- p_mimes_allowed  => ''application/json'',',
'        p_source         => C_POST_SOURCE',
'    );',
'    ords.define_handler(',
'        p_module_name    => l_module_name,',
'        p_pattern        => ''mcp'',',
'        p_method         => ''DELETE'',',
'        p_source_type    => ''plsql/block'',',
'        -- p_mimes_allowed  => ''application/json'',',
'        p_source         => C_DELETE_SOURCE',
'    );',
'end;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_imp.id(33058342185747337)
,p_internal_uid=>12082326290064435
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(28800302447227107)
,p_process_sequence=>30
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Delete MCP Handler'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'declare',
'    l_module_name varchar2(80);',
'begin',
'    l_module_name := lower(:P3_MODULE_NAME);',
'    ords.delete_module(',
'        p_module_name    => l_module_name',
'    );',
'end;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
