'    p_json_schema => l_schema,',
'    p_tags => apex_string.split(:P5_TAGS,'','')',
'  );',
'  insert into oj_mcp_tools_extras(tool_id, resource_id, output_schema, visibility)',
'  values(l_tool_id, :P5_RESOURCE_ID, :P5_OUTPUT_SCHEMA, :P5_VISIBILITY);',
'end;'))
