prompt --application/pages/page_01001
begin
wwv_flow_imp_page.create_page(
 p_id=>1001
,p_name=>'get_current_user'
,p_alias=>'GET-CURRENT-USER'
,p_step_title=>'get_current_user'
,p_autocomplete_on_off=>'OFF'
,p_javascript_code=>wwv_flow_string.join(wwv_flow_t_varchar2(
'import { App, applyHostStyleVariables, applyDocumentTheme }',
'    from ''https://cdn.jsdelivr.net/npm/@modelcontextprotocol/ext-apps@1.1.2/+esm'';',
'',
'const statusEl = document.getElementById(''status'');',
'const resultEl = document.getElementById(''result'');',
'const btn = document.getElementById(''btn'');',
'',
unistr('// \2500\2500 helpers \2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500'),
'function esc(s) {',
'    return String(s)',
'        .replace(/&/g, ''&amp;'').replace(/</g, ''&lt;'')',
'        .replace(/>/g, ''&gt;'').replace(/"/g, ''&quot;'');',
'}',
'',
'function showResult(cls, label, value) {',
'    resultEl.className = cls;',
'    resultEl.innerHTML =',
'        `<div class="lbl">${esc(label)}</div><div class="val">${esc(value)}</div>`;',
'    resultEl.style.display = ''block'';',
'    statusEl.textContent = '''';',
'    btn.disabled = false;',
'    btn.textContent = ''Refresh'';',
'}',
'',
'function handleResult(result) {',
'    const content = result?.result?.content ?? result?.content ?? [];',
'    const block = content.find(c => c.type === ''text'');',
'    const text = block?.text ?? JSON.stringify(result);',
'    let parsed = null;',
'    try { parsed = JSON.parse(text); } catch (_) { }',
'    if (parsed?.username) showResult(''success'', ''Username'', parsed.username);',
'    else if (parsed?.result) showResult(''error'', ''Notice'', parsed.result);',
'    else showResult(''success'', ''Response'', text);',
'}',
'',
unistr('// \2500\2500 App setup \2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500'),
'const app = new App(',
'    { name: ''get-current-user-app'', version: ''1.0.0'' },',
'    {},',
'    { autoResize: true, initialSize: { width: 1140 } }',
');',
'',
'// Bug 1 workaround: suppress the "Not connected" / Zod parse error that',
'// Claude Desktop triggers by sending host-context-changed BEFORE the',
'// ui/initialize handshake completes.  We swallow the error here and',
'// install the real error handler only after connect() succeeds.',
'app.onerror = (_err) => { /* intentionally ignored during init */ };',
'',
'// Apply theme / style variables when the host context changes.',
'app.onhostcontextchanged = (ctx) => {',
'    if (ctx?.theme) applyDocumentTheme(ctx.theme);',
'    if (ctx?.styles?.variables) applyHostStyleVariables(ctx.styles.variables);',
'};',
'',
unistr('// \2500\2500 Button: call get_current_user tool directly \2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500'),
'btn.addEventListener(''click'', async () => {',
'    btn.disabled = true;',
'    btn.textContent = ''Fetching...'';',
'    statusEl.textContent = ''Requesting current user...'';',
'    resultEl.style.display = ''none'';',
'',
'    try {',
'        const result = await app.callServerTool({ "name": "get_current_user" });',
'        handleResult(result);',
'    } catch (err) {',
'        showResult(''error'', ''Error'', err?.message ?? String(err));',
'    }',
'});',
'',
unistr('// \2500\2500 Connect \2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500\2500'),
'try {',
'    statusEl.textContent = ''Connecting...'';',
'    await app.connect();',
'',
'    // Install a real error handler now that init is complete.',
'    app.onerror = (err) => {',
'        statusEl.textContent = ''Error: '' + (err?.message ?? String(err));',
'    };',
'',
'    // Apply initial host context (theme, styles).',
'    const ctx = app.getHostContext();',
'    if (ctx?.theme) applyDocumentTheme(ctx.theme);',
'    if (ctx?.styles?.variables) applyHostStyleVariables(ctx.styles.variables);',
'',
'    statusEl.textContent = ''Waiting for result...'';',
'    btn.disabled = false;',
'    btn.textContent = ''Get Current User'';',
'',
'} catch (err) {',
'    // Install real error handler even on failure so future errors are visible.',
'    app.onerror = (e) => {',
'        statusEl.textContent = ''Error: '' + (e?.message ?? String(e));',
'    };',
'    statusEl.textContent = ''Init failed: '' + (err?.message ?? String(err));',
'    btn.disabled = false;',
'    btn.textContent = ''Get Current User'';',
'}'))
,p_inline_css=>wwv_flow_string.join(wwv_flow_t_varchar2(
